import {renderHook} from '@testing-library/react';
import React from 'react';
import {QueryClient, QueryClientProvider} from 'react-query';
import {usePromotionalProducts} from '../../../hooks/queries/recommendations';
import useTrendingProducts from './useTrendingProducts';

jest.mock('../../../hooks/queries/recommendations');

let mockFeatureFlagValue = null;

jest.mock('../../../utils/constants/signalmanConstants', () => ({
  get boostedPromoProductsTest() {
    return mockFeatureFlagValue;
  }
}));

describe('useTrendingProducts', () => {
  const createWrapper = () => {
    const queryClient = new QueryClient({
      defaultOptions: {
        queries: {
          retry: false
        }
      }
    });

    return ({children}) => (
      <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
    );
  };

  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe('Success State', () => {
    it('should return products when data is available', () => {
      const mockProducts = [
        {
          image_src: 'image1.jpg',
          name: 'Product 1',
          style_id: '123'
        },
        {
          image_src: 'image2.jpg',
          name: 'Product 2',
          style_id: '456'
        }
      ];

      usePromotionalProducts.mockReturnValue({
        data: {products: mockProducts},
        isError: false,
        isLoading: false
      });

      const {result} = renderHook(
        () => useTrendingProducts({isEnabled: true}),
        {
          wrapper: createWrapper()
        }
      );

      expect(result.current.isLoading).toBe(false);
      expect(result.current.products).toEqual(mockProducts);
    });

    it('should pass correct query parameters', () => {
      usePromotionalProducts.mockReturnValue({
        data: {products: []},
        isError: false,
        isLoading: false
      });

      renderHook(() => useTrendingProducts({isEnabled: true}), {
        wrapper: createWrapper()
      });

      expect(usePromotionalProducts).toHaveBeenCalledWith({
        queryParams: {
          categoryId: 218,
          isEnabled: true,
          limit: 20,
          withBoostedProducts: undefined
        }
      });
    });
  });

  describe('Loading State', () => {
    it('should return loading state', () => {
      usePromotionalProducts.mockReturnValue({
        data: undefined,
        isError: false,
        isLoading: true
      });

      const {result} = renderHook(
        () => useTrendingProducts({isEnabled: true}),
        {
          wrapper: createWrapper()
        }
      );

      expect(result.current.isLoading).toBe(true);
      expect(result.current.products).toEqual([]);
    });
  });

  describe('Error State', () => {
    it('should return empty products on error', () => {
      usePromotionalProducts.mockReturnValue({
        data: undefined,
        isError: true,
        isLoading: false
      });

      const {result} = renderHook(
        () => useTrendingProducts({isEnabled: true}),
        {
          wrapper: createWrapper()
        }
      );

      expect(result.current.isLoading).toBe(false);
      expect(result.current.products).toEqual([]);
    });
  });

  describe('Empty Data Handling', () => {
    it('should return empty products when data is null', () => {
      usePromotionalProducts.mockReturnValue({
        data: null,
        isError: false,
        isLoading: false
      });

      const {result} = renderHook(
        () => useTrendingProducts({isEnabled: true}),
        {
          wrapper: createWrapper()
        }
      );

      expect(result.current.isLoading).toBe(false);
      expect(result.current.products).toEqual([]);
    });

    it('should return empty products when products array is empty', () => {
      usePromotionalProducts.mockReturnValue({
        data: {products: []},
        isError: false,
        isLoading: false
      });

      const {result} = renderHook(
        () => useTrendingProducts({isEnabled: true}),
        {
          wrapper: createWrapper()
        }
      );

      expect(result.current.isLoading).toBe(false);
      expect(result.current.products).toEqual([]);
    });

    it('should return empty products when products property is missing', () => {
      usePromotionalProducts.mockReturnValue({
        data: {},
        isError: false,
        isLoading: false
      });

      const {result} = renderHook(
        () => useTrendingProducts({isEnabled: true}),
        {
          wrapper: createWrapper()
        }
      );

      expect(result.current.isLoading).toBe(false);
      expect(result.current.products).toEqual([]);
    });

    it('should return empty products when products is not an array', () => {
      usePromotionalProducts.mockReturnValue({
        data: {products: null},
        isError: false,
        isLoading: false
      });

      const {result} = renderHook(
        () => useTrendingProducts({isEnabled: true}),
        {
          wrapper: createWrapper()
        }
      );

      expect(result.current.isLoading).toBe(false);
      expect(result.current.products).toEqual([]);
    });
  });

  describe('Data Transformation', () => {
    it('should return products as-is without transformation', () => {
      const mockProducts = [
        {
          custom_field: 'custom_value',
          name: 'Special Product',
          style_id: '789'
        }
      ];

      usePromotionalProducts.mockReturnValue({
        data: {products: mockProducts},
        isError: false,
        isLoading: false
      });

      const {result} = renderHook(
        () => useTrendingProducts({isEnabled: true}),
        {
          wrapper: createWrapper()
        }
      );

      expect(result.current.products).toEqual(mockProducts);
      expect(result.current.products[0].custom_field).toBe('custom_value');
    });
  });

  describe('Hook Re-rendering', () => {
    it('should update when loading state changes', () => {
      const {rerender, result} = renderHook(
        () => useTrendingProducts({isEnabled: true}),
        {
          wrapper: createWrapper()
        }
      );

      usePromotionalProducts.mockReturnValue({
        data: undefined,
        isError: false,
        isLoading: true
      });

      rerender();
      expect(result.current.isLoading).toBe(true);

      const mockProducts = [{name: 'New Product', style_id: '999'}];
      usePromotionalProducts.mockReturnValue({
        data: {products: mockProducts},
        isError: false,
        isLoading: false
      });

      rerender();
      expect(result.current.isLoading).toBe(false);
      expect(result.current.products).toEqual(mockProducts);
    });

    it('should handle transition from success to error state', () => {
      const mockProducts = [{name: 'Product', style_id: '111'}];

      usePromotionalProducts.mockReturnValue({
        data: {products: mockProducts},
        isError: false,
        isLoading: false
      });

      const {rerender, result} = renderHook(
        () => useTrendingProducts({isEnabled: true}),
        {
          wrapper: createWrapper()
        }
      );

      expect(result.current.products).toEqual(mockProducts);

      usePromotionalProducts.mockReturnValue({
        data: undefined,
        isError: true,
        isLoading: false
      });

      rerender();
      expect(result.current.products).toEqual([]);
      expect(result.current.isLoading).toBe(false);
    });
  });

  describe('Boosted Products Feature Flag', () => {
    beforeEach(() => {
      jest.clearAllMocks();
      mockFeatureFlagValue = null;
    });

    it('should pass withBoostedProducts=true when flag is "test"', () => {
      mockFeatureFlagValue = 'test';

      usePromotionalProducts.mockReturnValue({
        data: {products: []},
        isError: false,
        isLoading: false
      });

      renderHook(() => useTrendingProducts({isEnabled: true}), {
        wrapper: createWrapper()
      });

      expect(usePromotionalProducts).toHaveBeenCalledWith({
        queryParams: {
          categoryId: 218,
          isEnabled: true,
          limit: 20,
          withBoostedProducts: true
        }
      });
    });

    it('should pass withBoostedProducts=undefined when flag is "excluded"', () => {
      mockFeatureFlagValue = 'excluded';

      usePromotionalProducts.mockReturnValue({
        data: {products: []},
        isError: false,
        isLoading: false
      });

      renderHook(() => useTrendingProducts({isEnabled: true}), {
        wrapper: createWrapper()
      });

      expect(usePromotionalProducts).toHaveBeenCalledWith({
        queryParams: {
          categoryId: 218,
          isEnabled: true,
          limit: 20,
          withBoostedProducts: undefined
        }
      });
    });

    it('should pass withBoostedProducts=undefined when flag is null', () => {
      mockFeatureFlagValue = null;

      usePromotionalProducts.mockReturnValue({
        data: {products: []},
        isError: false,
        isLoading: false
      });

      renderHook(() => useTrendingProducts({isEnabled: true}), {
        wrapper: createWrapper()
      });

      expect(usePromotionalProducts).toHaveBeenCalledWith({
        queryParams: {
          categoryId: 218,
          isEnabled: true,
          limit: 20,
          withBoostedProducts: undefined
        }
      });
    });

    it('should pass withBoostedProducts=undefined when flag is "control"', () => {
      mockFeatureFlagValue = 'control';

      usePromotionalProducts.mockReturnValue({
        data: {products: []},
        isError: false,
        isLoading: false
      });

      renderHook(() => useTrendingProducts({isEnabled: true}), {
        wrapper: createWrapper()
      });

      expect(usePromotionalProducts).toHaveBeenCalledWith({
        queryParams: {
          categoryId: 218,
          isEnabled: true,
          limit: 20,
          withBoostedProducts: undefined
        }
      });
    });
  });
});

