import 'keen-slider/keen-slider.min.css';
import {semantics} from '@customink/design-tokens';
import {
  ArrowDownIcon,
  Box,
  IconButton,
  Typography
} from '@customink/pigment-react';
import {styled} from '@mui/material/styles';
import useResizeObserver from '@react-hook/resize-observer';
import KeenSlider from 'keen-slider';
import PropTypes from 'prop-types';
import React, {useCallback, useEffect, useRef, useState} from 'react';
import FavoritesProvider, {
  PageType
} from 'features/favorites/FavoritesProvider';
import useTrendingProductsWrapper from 'hooks/queries/useTrendingProductsWrapper';
import useBreakpoint from 'hooks/useBreakpoint';
import RelatedProductCard from 'product_details_page/RelatedProducts/RelatedProductCard';
import {CATEGORY_PROMOTIONAL_PRODUCTS} from 'utils/constants/categoryConstants';
import createRecoCardLinkHref from 'utils/createRecoCardLinkHref';
import {CarouselSkeleton} from './components/LoadingSkeleton';
import {
  fireABTestGroupEvent,
  firePromoTrendingRecommendationClickEvent,
  firePromoTrendingRecommendationViewEvent
} from 'utils/metrics/trendingPromoProducts';
import {boostedPromoProductsTest} from 'utils/constants/signalmanConstants';

const Container = styled(Box)(() => ({
  marginBottom: '2.5rem',
  marginTop: '2.5rem',
  width: '100%'
}));

const TrendingProductsHeader = styled(Box)(({isMobile}) => ({
  marginBottom: isMobile ? '0.8125rem' : '0.28125rem',
  textAlign: 'left'
}));

const CarouselContainer = styled('div')(() => ({
  display: 'flex',
  height: 'max-content',
  position: 'relative',
  width: '100%'
}));

const SliderWrapper = styled('div')(() => ({
  '.arrow-container': {
    '.arrow': {
      '&.disabled': {
        backgroundColor: 'transparent',
        boxShadow: 'none',
        cursor: 'default'
      },
      '&.left svg': {transform: 'rotate(90deg) !important;'},
      '&.right svg': {transform: 'rotate(-90deg);'},
      '&:active': {
        backgroundColor: semantics.light.neutral.background.subtleOpaque
      },
      '&:hover': {
        backgroundColor: semantics.light.neutral.background.subtleOpaque
      },
      backgroundColor: semantics.light.neutral.background.primary,
      boxShadow: '0 0.25rem 0.5rem rgba(0, 0, 0, 0.08)',
      fontSize: '1.25rem',
      height: '2rem',
      margin: '0 0.5rem',
      pointerEvents: 'auto',
      width: '2rem',
      zIndex: 1
    },
    alignItems: 'center',
    bottom: 0,
    display: 'flex',
    justifyContent: 'space-between',
    left: 0,
    position: 'absolute',
    right: 0,
    top: 0
  },
  '.keen-slider': {
    display: 'flex !important',
    height: '100%',
    overflow: 'hidden !important',
    position: 'relative',
    touchAction: 'pan-y',
    userSelect: 'none',
    WebkitTouchCallout: 'none'
  },
  '.keen-slider__slide': {
    minHeight: '100%',
    overflow: 'hidden',
    position: 'relative'
  },
  '.slide_auto_width': {
    '@media (max-width: 1023px)': {
      marginRight: '1rem'
    },
    marginRight: '1rem',
    maxWidth: '19.25rem',
    width: '100%'
  },
  backgroundColor: 'transparent',
  height: '100%',
  overflow: 'hidden',
  position: 'relative',
  width: '100%'
}));

const TrendingCarousel = ({
  categoryId = CATEGORY_PROMOTIONAL_PRODUCTS,
  categoryName = '',
  onProductClick,
  title = 'Trending Products'
}) => {
  const breakpoint = useBreakpoint();
  const isMobile = breakpoint === 'sm';
  const {isLoading, products} = useTrendingProductsWrapper({categoryId});

  const [isFirstSlide, setIsFirstSlide] = useState(true);
  const [isLastSlide, setIsLastSlide] = useState(false);
  const hasFiredABTestEvent = useRef(false);

  useEffect(() => {
    if (
      categoryId === CATEGORY_PROMOTIONAL_PRODUCTS &&
      products.length > 0 &&
      !hasFiredABTestEvent.current
    ) {
      fireABTestGroupEvent(boostedPromoProductsTest);
      hasFiredABTestEvent.current = true;
    }
  }, [categoryId, products]);

  const getSlidesPerView = () => {
    if (isMobile) {
      return products.length >= 3 ? 1.6 : 'auto';
    }
    return products.length >= 5 ? 4 : 'auto';
  };

  const slidesPerView = getSlidesPerView();
  const gap = isMobile ? 8 : 16;

  const sliderRef = useRef(null);
  const instanceRef = useRef(null);

  useEffect(() => {
    if (sliderRef.current && products.length > 0) {
      instanceRef.current = new KeenSlider(sliderRef.current, {
        created: () => {
          setIsFirstSlide(true);
          setIsLastSlide(false);
        },
        initial: 0,
        loop: true,
        mode: 'snap',
        slideChanged: () => {
          setIsFirstSlide(false);
          setIsLastSlide(false);
        },
        slidesPerView,
        spacing: gap
      });
    }

    return () => {
      if (instanceRef.current) {
        instanceRef.current.destroy();
        instanceRef.current = null;
      }
    };
  }, [products.length, slidesPerView, gap, isMobile]);

  const boundingBoxRef = useRef(null);
  const hasFiredViewEvent = useRef(false);
  useResizeObserver(boundingBoxRef, () => instanceRef?.current?.refresh());

  useEffect(() => {
    if (
      !boundingBoxRef.current ||
      products.length === 0 ||
      hasFiredViewEvent.current
    ) {
      return;
    }

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting && !hasFiredViewEvent.current) {
            firePromoTrendingRecommendationViewEvent({categoryName});
            hasFiredViewEvent.current = true;
          }
        });
      },
      {threshold: 0.1}
    );

    observer.observe(boundingBoxRef.current);

    return () => {
      observer.disconnect();
    };
  }, [categoryId, categoryName, products]);

  const handleLeftClick = useCallback((e) => {
    e.stopPropagation();
    if (instanceRef?.current?.prev) {
      instanceRef.current.prev();
    }
  }, []);

  const handleRightClick = useCallback((e) => {
    e.stopPropagation();
    if (instanceRef?.current?.next) {
      instanceRef.current.next();
    }
  }, []);

  if (isLoading) {
    return <CarouselSkeleton />;
  }

  if (products.length === 0) {
    return null;
  }

  const showArrows = slidesPerView !== 'auto' && !isMobile;

  const productCards = products.map((product) => (
    <RelatedProductCard
      key={`trending-carousel-${product.style_id}`}
      sx={{
        width: '100%',
        ...(isMobile && {
          '& .MuiCardContent-root': {
            display: 'flex',
            flex: '1 1 auto',
            flexDirection: 'column',
            gap: '0.25rem !important',
            minHeight: 'calc(100% - 13rem) !important',
            padding: '0.5rem !important'
          },
          '& .rpc-image-wrapper': {
            flexShrink: 0,
            height: '10.3125rem !important',
            paddingTop: '0 !important',
            width: '100% !important'
          },
          '& [data-testid="reco-product-name"]': {
            marginBottom: '0 !important',
            minHeight: '2rem',
            WebkitLineClamp: 2
          },
          height: '22rem'
        })
      }}
      onClick={() => {
        firePromoTrendingRecommendationClickEvent(product);
        if (onProductClick) {
          onProductClick(product);
        }
      }}
      linkHref={createRecoCardLinkHref({
        stylePath: product.link
      })}
      imageSrc={product.image_src}
      imageSrcSet={product.image_srcset || ''}
      minQty={product.min_qty}
      name={product.name}
      ratingCount={product.rating_count}
      ratingScore={product.rating_score}
      sizing={product.sizing}
      generalComments={product.general_comments || ''}
      defaultUnitPrices={product.default_unit_prices}
      primaryCategoryId={product.primary_category_id}
      styleType={product.style_type}
      defaultQuoteQty={product.default_quote_qty}
      productId={product.style_id}
      styleId={product.style_id}
      widgetType="trending"
      categories={
        product.categories || [
          {
            id: product.primary_category_id,
            name: product.primary_category_name
          }
        ]
      }
    />
  ));

  return (
    <FavoritesProvider pageType={PageType.SUBCATEGORY}>
      <Container>
        <TrendingProductsHeader isMobile={isMobile}>
          <Typography
            sx={{
              color: semantics.light.neutral.text.primary,
              fontSize: '1.5rem',
              fontWeight: 700,
              lineHeight: 1.25
            }}>
            {title}
          </Typography>
        </TrendingProductsHeader>
        <CarouselContainer>
          <SliderWrapper ref={boundingBoxRef}>
            {showArrows && (
              <div className="arrow-container">
                <IconButton
                  disableRipple
                  className={`arrow left ${isFirstSlide ? 'disabled' : ''}`}
                  onClick={handleLeftClick}
                  disabled={isFirstSlide}
                  aria-label="Previous products">
                  <ArrowDownIcon
                    sx={{fill: semantics.light.neutral.icon.default}}
                    fontSize="inherit"
                  />
                </IconButton>

                <IconButton
                  disableRipple
                  className={`arrow right ${isLastSlide ? 'disabled' : ''}`}
                  onClick={handleRightClick}
                  disabled={isLastSlide}
                  aria-label="Next products">
                  <ArrowDownIcon
                    sx={{fill: semantics.light.neutral.icon.default}}
                    fontSize="inherit"
                  />
                </IconButton>
              </div>
            )}
            <div
              ref={sliderRef}
              className="keen-slider"
              style={{paddingRight: '0'}}>
              {productCards.map((slide, i) => (
                <div
                  key={slide.key}
                  className={`keen-slider__slide slide-${i} ${slidesPerView === 'auto' ? 'slide_auto_width' : ''}`}>
                  {slide}
                </div>
              ))}
            </div>
          </SliderWrapper>
        </CarouselContainer>
      </Container>
    </FavoritesProvider>
  );
};

TrendingCarousel.propTypes = {
  categoryId: PropTypes.number,
  categoryName: PropTypes.string,
  onProductClick: PropTypes.func,
  title: PropTypes.string
};

export default TrendingCarousel;

