import {useQuery} from 'react-query';
import config from '../../config';

// Environment-specific value is baked in at build time via Parameter Store
const recoApiUrl = () => config.services.recommendations.apiUrl;

const fetchRecommendedStyles = async ({colorId, limit = 4, styleId}) => {
  const queryParams = new URLSearchParams();
  if (colorId) {
    queryParams.append('colorId', colorId);
  }
  if (limit) {
    queryParams.append('limit', limit);
  }

  const relatedProductsEndpointUrl = `${recoApiUrl()}/api/v1/related-products/${styleId}${queryParams ? `?${queryParams}` : ''}`;

  const response = await fetch(relatedProductsEndpointUrl);
  if (!response.ok) {
    throw new Error('Failed to fetch recommended styles', {
      response,
      styleId
    });
  }
  return response.json();
};

const useRecommendedStyles = (styleId, options = {}) => {
  const {colorId, limit = 4} = options?.queryParams || {};
  return useQuery({
    queryFn: () =>
      fetchRecommendedStyles({
        colorId,
        limit,
        styleId
      }),
    queryKey: ['recommendations', styleId, colorId, limit],
    ...options
  });
};

const fetchPromotionalProducts = async ({
  categoryId,
  limit = 6,
  withBoostedProducts
}) => {
  const queryParams = new URLSearchParams();
  if (categoryId) {
    queryParams.append('categoryId', categoryId);
  }
  if (limit) {
    queryParams.append('limit', limit);
  }
  if (withBoostedProducts && typeof withBoostedProducts === 'boolean') {
    queryParams.append('withBoostedProducts', withBoostedProducts);
  }
  const response = await fetch(
    `${recoApiUrl()}/api/v1/promotional-products${queryParams ? `?${queryParams}` : ''}`
  );
  if (!response.ok) {
    throw new Error('Failed to fetch promotional products', {
      categoryId,
      response
    });
  }
  return response.json();
};

export const usePromotionalProducts = (options = {}) => {
  const {
    categoryId = 218,
    isEnabled,
    limit = 20,
    withBoostedProducts
  } = options?.queryParams || {};
  return useQuery({
    enabled: isEnabled,
    queryFn: () =>
      fetchPromotionalProducts({categoryId, limit, withBoostedProducts}),
    queryKey: ['promotional-products', categoryId, limit, withBoostedProducts],
    ...options
  });
};

const fetchTrendingProductsByCategoryId = async ({categoryId, limit = 10}) => {
  const queryParams = new URLSearchParams();
  if (categoryId) {
    queryParams.append('categoryId', categoryId);
  }
  if (limit) {
    queryParams.append('limit', limit);
  }
  const response = await fetch(
    `${recoApiUrl()}/api/v1/trending-products/by-category${queryParams ? `?${queryParams}` : ''}`
  );
  if (!response.ok) {
    throw new Error('Failed to fetch trending products', {
      categoryId,
      response
    });
  }
  return response.json();
};

export const useTrendingProductsByCategoryId = (queryParams, options = {}) => {
  const {categoryId, isEnabled, limit = 20} = queryParams ?? {};
  return useQuery({
    enabled: isEnabled,
    queryFn: () => fetchTrendingProductsByCategoryId({categoryId, limit}),
    queryKey: ['trending-products', categoryId, limit],
    ...options
  });
};

const fetchMarchPromoProducts = async ({limit = 20}) => {
  const queryParams = new URLSearchParams();
  if (limit) {
    queryParams.append('limit', limit);
  }
  const response = await fetch(
    `${recoApiUrl()}/api/v1/march-promo${queryParams ? `?${queryParams}` : ''}`
  );
  if (!response.ok) {
    throw new Error('Failed to fetch march promo products', {
      cause: response
    });
  }
  return response.json();
};

export const useMarchPromoProducts = (options = {}) => {
  const {isEnabled, limit = 20} = options?.queryParams || {};
  return useQuery({
    enabled: isEnabled,
    queryFn: () => fetchMarchPromoProducts({limit}),
    queryKey: ['march-promo-products', limit],
